public class Computer{private String cpu,ram,storage;private Computer(Builder b){cpu=b.cpu;ram=b.ram;storage=b.storage;}public String toString(){return cpu+" "+ram+" "+storage;}public static class Builder{private String cpu,ram,storage;public Builder cpu(String v){cpu=v;return this;}public Builder ram(String v){ram=v;return this;}public Builder storage(String v){storage=v;return this;}public Computer build(){return new Computer(this);}}}